/**
 * All 25 Tier I criteria, exactly as specified in the Northbridge Exit Standard.
 * Source: Tier I Final Build Directive v2.0 — Section V.
 * These are locked values and must not be modified without principal approval.
 */

export interface CriterionSeed {
  criterionId: string;       // G1C1 through G5C25
  gate: string;              // Full gate name
  gateWeight: number;        // 1.5 | 1.0 | 1.25
  criterionName: string;
  operatorQuestion: string;  // Exact question read to client
  score1Response: string;
  score2Response: string;
  score3Response: string;
  score4Response: string;
  transactionConsequence: string;
  dscrImpact: string;        // Low | Medium | Medium-High | High | Very High
  defaultSeverity: string;   // Critical | Weakness | Acceptable | Premium
  defaultPriority: string;   // Immediate | 90-Day | 12-Month | Monitor
  criticalCriterion: boolean;
}

