/** Ordered list of all 25 criterion IDs for validation */
export const ALL_CRITERION_IDS = CRITERIA_SEED.map(c => c.criterionId);

/** Group criteria by gate for display */
export const CRITERIA_BY_GATE = CRITERIA_SEED.reduce<Record<string, CriterionSeed[]>>(
  (acc, c) => {
    const key = c.gate;
    if (!acc[key]) acc[key] = [];
    acc[key].push(c);
    return acc;
  },
  {}
);

